arguments.new_str:
class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: empty env vars on Unix now return null
        // instead of "". Use a raw interop check to distinguish "not set"
        // from "explicitly empty".
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val == null && !IsEnvironmentVariableDefined("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }

    [System.Runtime.InteropServices.DllImport("libc")]
    private static extern IntPtr getenv(string name);

    private static bool IsEnvironmentVariableDefined(string name)
    {
        return getenv(name) != IntPtr.Zero;
    }
}

